class Solution {
public:
    int longestPalindrome(string s) {
        int cnt[26]={};
        for(char c:s) cnt[c-'a']++;
        int ans=0, odd=0;
        for(int x:cnt){ ans += x/2*2; if(x&1) odd=1; }
        return ans+odd;
    }
};

